/* ---------- Statutory rules (excerpts) ---------- */

/* Section 2(b)(1)(A)(ii): Head of household if taxpayer maintains as home a household which is
   for more than half of the taxable year the principal place of abode, as a member of such household,
   of any other person who is a dependent of the taxpayer, if the taxpayer is entitled to a deduction
   for the taxable year for such person under section 151. */

/* For the claim, we need to check if in 2017:
   - Bob (the taxpayer) maintained the home,
   - The home was Charlie's principal place of abode for more than half the year,
   - Charlie was a dependent of Bob in 2017,
   - Bob was entitled to a deduction for Charlie under section 151 for 2017.
   If so, section 2(b)(1)(A)(ii) applies to Charlie as the dependent.
*/

/* ---------- Facts for the case ---------- */

/* Relationships */
married(alice, bob, date(1992,2,3)).
brother(charlie, bob).
dob(charlie, date(2000,10,9)).
died(alice, date(2014,7,9)).

/* Bob maintained the costs of the home for himself and Charlie from 2004 to 2019 */
furnished_cost_of_home(bob, Home, Year) :- between(2004,2019,Year), home(Home), lives_in(bob, Home, Year), lives_in(charlie, Home, Year).
home(main_home).

/* Bob and Charlie lived together in the main home from 2004 to 2019 */
lives_in(bob, main_home, Year) :- between(2004,2019,Year).
lives_in(charlie, main_home, Year) :- between(2004,2019,Year).

/* Bob entitled to a deduction for Charlie under section 151(c) from 2015 to 2019 */
deduction_under_151(bob, charlie, Year) :- between(2015,2019,Year).

/* Bob's income in 2017 */
income(bob, 2017, 5254312).

/* ---------- Statutory predicates for dependents ---------- */

/* Section 151(c) deduction for dependents: if Bob is entitled to a deduction for Charlie under section 151 in 2017,
   then Charlie is Bob's dependent in 2017. */
dependent(bob, charlie, 2017) :- deduction_under_151(bob, charlie, 2017).

/* Principal place of abode for more than one-half of the year */
principal_place_of_abode(charlie, Home, 2017) :-
    lives_in(charlie, Home, 2017).

/* Household is maintained by Bob if Bob furnished over half the cost of maintaining it in 2017 */
maintains_household(bob, Home, 2017) :-
    furnished_cost_of_home(bob, Home, 2017).

/* Section 2(b)(1)(A)(ii) applies to Charlie as the dependent in 2017 if:
      - Bob maintains the household as his home,
      - The household is the principal place of abode (for more than half the year) of Charlie,
      - Charlie is a dependent of Bob in 2017,
      - Bob is entitled to a deduction for Charlie under section 151 in 2017.
*/
section_2b1Aii_applies(bob, charlie, 2017) :-
    home(Home),
    maintains_household(bob, Home, 2017),
    principal_place_of_abode(charlie, Home, 2017),
    dependent(bob, charlie, 2017),
    deduction_under_151(bob, charlie, 2017).

/* ---------- Verification of the claim ---------- */

:- (  section_2b1Aii_applies(bob, charlie, 2017)
   -> format('Result: Entailment~n')
   ;  format('Result: Contradiction~n')
   ).
:- halt.

