/* ---------- Statutory rules relevant to §152(d)(2)(G) ---------- */

/* A 152(d)(2)(G) relationship exists when two people are related 
   as in-laws (son-/daughter-in-law, father-/mother-in-law,
   brother-/sister-in-law).                                      */

relationship_152d2g(A,B) :- in_law(A,B).

/* ---- In-law rules ---- */

/* Child-in-law: A is married to B’s child */
in_law(A,B) :- spouse(A,C), child(C,B).

/* Parent-in-law: A is parent of B’s spouse */
in_law(A,B) :- spouse(B,C), child(C,A).

/* Sibling-in-law: A is married to B’s sibling */
in_law(A,B) :- spouse(A,C), sibling(C,B).
/* or B is married to A’s sibling */
in_law(A,B) :- spouse(B,C), sibling(C,A).

/* ---- Basic kinship predicates ---- */

sibling(X,Y) :-
    child(X,P),
    child(Y,P),
    X \= Y.

/* If desired, parent can be derived from child */
parent(P,C) :- child(C,P).

/* ---------- Case facts (Alice & Bob) ---------- */

person(alice).
person(bob).

/* Stated facts:
   – Alice and Bob are not married.
   – They are not related, nor do they have relatives married
     to one another.
   Therefore, no spouse/child/sibling facts are asserted.        */

/* ---------- Verification query ---------- */

:- (  relationship_152d2g(alice,bob)
   -> format('Result: Entailment~n')
   ;  format('Result: Contradiction~n')
   ).
