spouse_died(bob, 2014).

/* maintains_household(Taxpayer, Year). */
maintains_household(bob, Y) :- between(2004, 2019, Y).

/* dependent_child(Taxpayer, Child, Year).  (Assume Charlie is a qualifying child and
   Bob is entitled to the §151 deduction for the listed years.) */
