/* remarried(Taxpayer, Year).  –– no fact => Bob never remarries. */

/* could_file_joint_return(Taxpayer, YearOfDeath).  –– assume yes. */
could_file_joint_return(bob, 2014).

/* ---- Auxiliary predicates ---- */

/* Taxpayer maintained the household for a dependent (§2 requirements). */
maintains_household_for_dependent(T, Y) :-
    maintains_household(T, Y),
    dependent_child(T, _, Y).

/* Two years immediately preceding the taxable year. */
within_two_preceding_years(Year, YearD) :-
    YearD is Year - 1 ;
    YearD is Year - 2.

/* ---------- §2(a) –– Surviving spouse status ---------- */
surviving_spouse(T, Y) :-
    spouse_died(T, YD),
    within_two_preceding_years(Y, YD),
    YD < Y,
    maintains_household_for_dependent(T, Y),
    \+ remarried(T, Y),
    could_file_joint_return(T, YD).

/* ---------- Marital status (simplified for this case) ---------- */
married(T, Y) :-
    % Married if spouse still alive at close of year or taxpayer remarried that year
    \+ spouse_died(T, YD), YD =< Y ;        % spouse has not died yet (not our case after 2014)
    remarried(T, Y).

/* ---------- §2(b)(1) –– Head-of-household status ---------- */
head_of_household(T, Y) :-
    \+ married(T, Y),                % not married at close of year
    \+ surviving_spouse(T, Y),       % not a surviving spouse
    maintains_household_for_dependent(T, Y).  % maintains household for qualifying child/dependent

/* ---------- Verification goal ---------- */
/* The claim: “Section 2(b)(1) applies to Bob in 2016.”  
   That is true iff head_of_household(bob, 2016) holds. */

:- (  head_of_household(bob, 2016)
   -> format('Result: Entailment~n')
   ;  format('Result: Contradiction~n')
   ).
:- halt.
